using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void TestInitialize()
        {
            _sut = new NotificationService();

            // Drain the static queue to prevent cross-test interference
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _sut.Dispose();
        }

        #region SendNotification with display name

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesNotificationWithDisplayNameMessage()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        #endregion

        #region SendNotification without display name

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdFormatInMessage()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", null, EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course (ID: 1050) has been created", notification.Message);
        }

        #endregion

        #region 3-param overload delegates to 5-param

        [TestMethod]
        public void SendNotification_ThreeParamOverload_DelegatesToFiveParamWithNullDisplayName()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", EntityOperation.CREATE);

            // Assert - should use ID format since display name is null
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course (ID: 1050) has been created", notification.Message);
        }

        #endregion

        #region ReceiveNotification returns enqueued notification

        [TestMethod]
        public void ReceiveNotification_AfterSend_ReturnsNotificationWithCorrectProperties()
        {
            // Arrange
            _sut.SendNotification("Student", "42", "Jane Doe", EntityOperation.UPDATE, "admin");

            // Act
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("UPDATE", notification.Operation);
            Assert.AreEqual("Student 'Jane Doe' has been updated", notification.Message);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.CreatedAt <= DateTime.Now);
            Assert.IsTrue(notification.CreatedAt > DateTime.Now.AddMinutes(-1));
        }

        #endregion

        #region ReceiveNotification returns null when empty

        [TestMethod]
        public void ReceiveNotification_WhenQueueIsEmpty_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        #endregion

        #region FIFO order

        [TestMethod]
        public void SendAndReceive_MultipleNotifications_ReturnedInFifoOrder()
        {
            // Arrange
            _sut.SendNotification("Course", "1", "Math", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", "Science", EntityOperation.UPDATE);
            _sut.SendNotification("Course", "3", "English", EntityOperation.DELETE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.IsNotNull(first);
            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("New Course 'Math' has been created", first.Message);

            var second = _sut.ReceiveNotification();
            Assert.IsNotNull(second);
            Assert.AreEqual("2", second.EntityId);
            Assert.AreEqual("Course 'Science' has been updated", second.Message);

            var third = _sut.ReceiveNotification();
            Assert.IsNotNull(third);
            Assert.AreEqual("3", third.EntityId);
            Assert.AreEqual("Course 'English' has been deleted", third.Message);
        }

        #endregion

        #region MarkAsRead does not throw

        [TestMethod]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            // Act & Assert - should not throw (no-op)
            _sut.MarkAsRead(0);
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(-1);
            _sut.MarkAsRead(int.MaxValue);
        }

        #endregion

        #region Dispose does not throw

        [TestMethod]
        public void Dispose_WhenCalled_DoesNotThrow()
        {
            // Act & Assert - should not throw
            _sut.Dispose();

            // Can still call Dispose again without issue
            _sut.Dispose();
        }

        #endregion

        #region Message format per operation (parameterized)

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Course 'Chemistry' has been created")]
        [DataRow(EntityOperation.UPDATE, "Course 'Chemistry' has been updated")]
        [DataRow(EntityOperation.DELETE, "Course 'Chemistry' has been deleted")]
        public void SendNotification_WithDisplayNameAndOperation_GeneratesCorrectMessage(
            EntityOperation operation, string expectedMessage)
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Course (ID: 1050) has been created")]
        [DataRow(EntityOperation.UPDATE, "Course (ID: 1050) has been updated")]
        [DataRow(EntityOperation.DELETE, "Course (ID: 1050) has been deleted")]
        public void SendNotification_WithoutDisplayNameAndOperation_GeneratesCorrectIdMessage(
            EntityOperation operation, string expectedMessage)
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", null, operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        #endregion

        #region CreatedBy defaults

        [TestMethod]
        public void SendNotification_WhenUserNameIsNull_CreatedByDefaultsToSystem()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WhenUserNameIsExplicitlyNull_CreatedByDefaultsToSystem()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WhenUserNameProvided_CreatedByUsesProvidedValue()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "jdoe");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("jdoe", notification.CreatedBy);
        }

        #endregion

        #region IsRead defaults to false

        [TestMethod]
        public void SendNotification_Always_IsReadDefaultsToFalse()
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsFalse(notification.IsRead);
        }

        #endregion

        #region Operation stores string representation

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "CREATE")]
        [DataRow(EntityOperation.UPDATE, "UPDATE")]
        [DataRow(EntityOperation.DELETE, "DELETE")]
        public void SendNotification_WithOperation_StoresStringRepresentation(
            EntityOperation operation, string expectedString)
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", "Chemistry", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedString, notification.Operation);
        }

        #endregion

        #region 3-param overload passes userName

        [TestMethod]
        public void SendNotification_ThreeParamOverloadWithUserName_PassesUserNameCorrectly()
        {
            // Arrange & Act
            _sut.SendNotification("Student", "5", EntityOperation.DELETE, "adminUser");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("adminUser", notification.CreatedBy);
            Assert.AreEqual("Student (ID: 5) has been deleted", notification.Message);
        }

        #endregion

        #region EntityType is preserved

        [TestMethod]
        public void SendNotification_WithEntityType_PreservesEntityType()
        {
            // Arrange & Act
            _sut.SendNotification("Instructor", "10", "Dr. Smith", EntityOperation.CREATE, "admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor", notification.EntityType);
        }

        #endregion

        #region Empty display name treated as null

        [TestMethod]
        [DataRow("")]
        [DataRow("   ")]
        public void SendNotification_WithEmptyOrWhitespaceDisplayName_UsesIdFormat(string displayName)
        {
            // Arrange & Act
            _sut.SendNotification("Course", "1050", displayName, EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course (ID: 1050) has been created", notification.Message);
        }

        #endregion
    }
}

