        {
            // Arrange
            var createdAt = new DateTime(2024, 6, 15, 10, 30, 0);
            var readAt = new DateTime(2024, 6, 15, 11, 0, 0);

            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Student created successfully",
                CreatedAt = createdAt,
                CreatedBy = "admin@contoso.edu",
                IsRead = true,
                ReadAt = readAt
            };

            // Assert
            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Student created successfully", notification.Message);
            Assert.AreEqual(createdAt, notification.CreatedAt);
            Assert.AreEqual("admin@contoso.edu", notification.CreatedBy);
            Assert.IsTrue(notification.IsRead);
            Assert.AreEqual(readAt, notification.ReadAt);
        }

        [TestMethod]
        public void Notification_IsRead_DefaultsToFalse()
        {
            // Arrange
            var notification = new Notification();

            // Act & Assert
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void Notification_ReadAt_DefaultsToNull()
        {
            // Arrange
            var notification = new Notification();

            // Act & Assert
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void Notification_CreatedBy_CanBeNull()
        {
            // Arrange — CreatedBy is not [Required], so null is valid
            var notification = new Notification
            {
                EntityType = "Course",
                EntityId = "101",
                Operation = "UPDATE",
                Message = "Course updated",
                CreatedAt = DateTime.UtcNow,
                CreatedBy = null
            };

            // Act & Assert
            Assert.IsNull(notification.CreatedBy);
        }

        [TestMethod]
        public void Notification_ReadAt_NullableDateTime_CanHaveValue()
        {
            // Arrange
            var readAt = new DateTime(2024, 1, 1, 12, 0, 0);
            var notification = new Notification { ReadAt = readAt };

            // Act & Assert
            Assert.IsTrue(notification.ReadAt.HasValue);
            Assert.AreEqual(readAt, notification.ReadAt.Value);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, 0)]
        [DataRow(EntityOperation.UPDATE, 1)]
        [DataRow(EntityOperation.DELETE, 2)]
        public void EntityOperation_EnumValues_HaveExpectedIntegerValues(EntityOperation operation, int expectedValue)
        {
            // Act & Assert
            Assert.AreEqual(expectedValue, (int)operation);
        }

        [TestMethod]
        public void EntityOperation_EnumCount_HasThreeValues()
        {
            // Arrange
            var values = Enum.GetValues(typeof(EntityOperation));

            // Act & Assert
            Assert.AreEqual(3, values.Length);
        }

        [TestMethod]
        [DataRow("CREATE")]
        [DataRow("UPDATE")]
        [DataRow("DELETE")]
        public void EntityOperation_Parse_ValidStringValues(string operationName)
        {
            // Act
            var parsed = Enum.Parse<EntityOperation>(operationName);

            // Assert
            Assert.IsTrue(Enum.IsDefined(typeof(EntityOperation), parsed));
        }
    }
