        [DataRow(10, 5, 2)]   // Math.Ceiling(10/5.0) = 2
        [DataRow(10, 10, 1)]  // Math.Ceiling(10/10.0) = 1
        [DataRow(1, 1, 1)]    // Math.Ceiling(1/1.0) = 1
