using System;
using System.Text.Json;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class NotificationsControllerTests
    {
        private NotificationService _drainHelper;

        private SchoolContext CreateContext(string dbName)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        [TestInitialize]
        public void TestInitialize()
        {
            // Drain the static notification queue to prevent cross-test interference
            _drainHelper = new NotificationService();
            while (_drainHelper.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _drainHelper?.Dispose();
        }

        [TestMethod]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
        {
            // Arrange
            using var context = CreateContext(nameof(GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList));
            using var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var json = JsonSerializer.Serialize(result.Value);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            Assert.IsTrue(root.GetProperty("success").GetBoolean());
            Assert.AreEqual(0, root.GetProperty("count").GetInt32());
            Assert.AreEqual(0, root.GetProperty("notifications").GetArrayLength());
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange
            using var context = CreateContext(nameof(GetNotifications_WithNotifications_ReturnsNotifications));
            using var controller = new NotificationsController(context);

            // Send some notifications via a separate NotificationService (same static queue)
            var sender = new NotificationService();
            sender.SendNotification("Course", "1", "Math", EntityOperation.CREATE);
            sender.SendNotification("Student", "2", "Jane", EntityOperation.UPDATE);
            sender.Dispose();

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var json = JsonSerializer.Serialize(result.Value);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            Assert.IsTrue(root.GetProperty("success").GetBoolean());
            Assert.AreEqual(2, root.GetProperty("count").GetInt32());

            var notifications = root.GetProperty("notifications");
            Assert.AreEqual(2, notifications.GetArrayLength());
        }

        [TestMethod]
        public void GetNotifications_LimitsToTen()
        {
            // Arrange
            using var context = CreateContext(nameof(GetNotifications_LimitsToTen));
            using var controller = new NotificationsController(context);

            // Send 15 notifications via a separate NotificationService (same static queue)
            var sender = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                sender.SendNotification("Course", i.ToString(), $"Course{i}", EntityOperation.CREATE);
            }
            sender.Dispose();

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var json = JsonSerializer.Serialize(result.Value);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            Assert.IsTrue(root.GetProperty("success").GetBoolean());
            Assert.AreEqual(10, root.GetProperty("count").GetInt32());
            Assert.AreEqual(10, root.GetProperty("notifications").GetArrayLength());
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Arrange
            using var context = CreateContext(nameof(MarkAsRead_ReturnsSuccess));
            using var controller = new NotificationsController(context);

            // Act
            var result = controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var json = JsonSerializer.Serialize(result.Value);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            Assert.IsTrue(root.GetProperty("success").GetBoolean());
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Arrange
            using var context = CreateContext(nameof(Index_ReturnsViewResult));
            using var controller = new NotificationsController(context);

            // Act
            var result = controller.Index();

            // Assert
            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }
    }
}

