using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class StudentsControllerTests
    {
        private NotificationService _notificationService;

        [TestInitialize]
        public void TestInitialize()
        {
            // Drain the static notification queue to prevent cross-test interference
            _notificationService = new NotificationService();
            while (_notificationService.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _notificationService?.Dispose();
        }

        private SchoolContext CreateContext(string dbName)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        private void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { LastName = "Adams", FirstMidName = "Alice", EnrollmentDate = new DateTime(2023, 9, 1) },
                new Student { LastName = "Brown", FirstMidName = "Bob", EnrollmentDate = new DateTime(2022, 1, 15) },
                new Student { LastName = "Clark", FirstMidName = "Charlie", EnrollmentDate = new DateTime(2024, 6, 10) }
            );
            context.SaveChanges();
        }

        #region Index

        [TestMethod]
        public void Index_DefaultSort_ReturnsSortedByLastName()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            Assert.AreEqual("Adams", model[0].LastName);
            Assert.AreEqual("Brown", model[1].LastName);
            Assert.AreEqual("Clark", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsSortedByLastNameDescending()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Clark", model[0].LastName);
            Assert.AreEqual("Brown", model[1].LastName);
            Assert.AreEqual("Adams", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsSortedByEnrollmentDate()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Brown (2022-01-15), Adams (2023-09-01), Clark (2024-06-10)
            Assert.AreEqual("Brown", model[0].LastName);
            Assert.AreEqual("Adams", model[1].LastName);
            Assert.AreEqual("Clark", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsSortedByEnrollmentDateDescending()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Clark (2024-06-10), Adams (2023-09-01), Brown (2022-01-15)
            Assert.AreEqual("Clark", model[0].LastName);
            Assert.AreEqual("Adams", model[1].LastName);
            Assert.AreEqual("Brown", model[2].LastName);
        }

        [TestMethod]
        public void Index_WithSearchString_FiltersResults()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act - search for "Alice" (FirstMidName)
            var result = controller.Index(null, null, "Alice", null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Adams", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act - searchString is null, currentFilter is "Brown"
            var result = controller.Index(null, "Brown", null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Brown", model[0].LastName);
        }

        [TestMethod]
        public void Index_NewSearchResetsPagination()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);
            var controller = new StudentsController(context);

            // Act - new search (searchString not null) should set page to 1
            var result = controller.Index(null, null, "Adams", 5) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // page should have been reset to 1; PageIndex reflects this
            Assert.AreEqual(1, model.PageIndex);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1),
                Enrollments = new System.Collections.Generic.List<Enrollment>()
            };
            context.Students.Add(student);
            context.SaveChanges();
            var studentId = student.ID;
            var controller = new StudentsController(context);

            // Act
            var result = controller.Details(studentId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Smith", model.LastName);
            Assert.AreEqual("John", model.FirstMidName);
        }

        #endregion

        #region Create GET

        [TestMethod]
        public void Create_GET_ReturnsViewWithStudent()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [TestMethod]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual("Doe", context.Students.First().LastName);
        }

        [TestMethod]
        public void Create_POST_InvalidEnrollmentDate_ReturnsView()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Doe", model.LastName);
            // Student should not have been saved
            Assert.AreEqual(0, context.Students.Count());
        }

        #endregion

        #region Edit GET

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Edit((int?)null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsView()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var student = new Student
            {
                LastName = "Jones",
                FirstMidName = "Tom",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            context.Students.Add(student);
            context.SaveChanges();
            var studentId = student.ID;
            var controller = new StudentsController(context);

            // Act
            var result = controller.Edit(studentId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Jones", model.LastName);
        }

        [TestMethod]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Edit(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit POST

        [TestMethod]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var student = new Student
            {
                LastName = "Original",
                FirstMidName = "Name",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            context.Students.Add(student);
            context.SaveChanges();
            var studentId = student.ID;

            // Detach so EF doesn't track the old entity when we attach the edited one
            context.Entry(student).State = EntityState.Detached;

            var controller = new StudentsController(context);
            var editedStudent = new Student
            {
                ID = studentId,
                LastName = "Updated",
                FirstMidName = "Name",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = controller.Edit(editedStudent) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var updatedStudent = context.Students.Find(studentId);
            Assert.AreEqual("Updated", updatedStudent.LastName);
        }

        #endregion

        #region Delete GET

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);

            // Act
            var result = controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsView()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            var student = new Student
            {
                LastName = "ToDelete",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
