            {
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 9, 1)
            };
            context.Departments.Add(department);
            context.SaveChanges();
            return department;
        }

        private Course SeedCourse(SchoolContext context, int departmentId, int courseId = 1050, string title = "Chemistry")
        {
            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = departmentId
            };
            context.Courses.Add(course);
            context.SaveChanges();
            return course;
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
