using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public class DbInitializerTests
    {
        #region Helper

        private SchoolContext CreateContext(string dbName)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            return new SchoolContext(options);
        }

        private SchoolContext CreateAndSeed(string dbName)
        {
            var context = CreateContext(dbName);
            DbInitializer.Initialize(context);
            return context;
        }

        #endregion

        #region Seed Count Tests

        [TestMethod]
        public void Initialize_SeedsStudents_Creates8Students()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsStudents_Creates8Students);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(8, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_SeedsInstructors_Creates5Instructors()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsInstructors_Creates5Instructors);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(5, context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_SeedsDepartments_Creates4Departments()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsDepartments_Creates4Departments);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(4, context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsCourses_Creates7Courses()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsCourses_Creates7Courses);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_SeedsOfficeAssignments_Creates3OfficeAssignments()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsOfficeAssignments_Creates3OfficeAssignments);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(3, context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsCourseAssignments_Creates8CourseAssignments()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsCourseAssignments_Creates8CourseAssignments);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsEnrollments_Creates11Enrollments()
        {
            // Arrange
            var dbName = nameof(Initialize_SeedsEnrollments_Creates11Enrollments);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            Assert.AreEqual(11, context.Enrollments.Count());
        }

        #endregion

        #region Idempotency Test

        [TestMethod]
        public void Initialize_IsIdempotent_DoesNotDuplicateData()
        {
            // Arrange
            var dbName = nameof(Initialize_IsIdempotent_DoesNotDuplicateData);
            using var context = CreateContext(dbName);

            // Act — call Initialize twice on the same database
            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            // Assert — counts should remain the same as a single seed
            Assert.AreEqual(8, context.Students.Count());
            Assert.AreEqual(5, context.Instructors.Count());
            Assert.AreEqual(4, context.Departments.Count());
            Assert.AreEqual(7, context.Courses.Count());
            Assert.AreEqual(3, context.OfficeAssignments.Count());
            Assert.AreEqual(8, context.CourseAssignments.Count());
            Assert.AreEqual(11, context.Enrollments.Count());
        }

        #endregion

        #region Student Data Verification Tests

        [TestMethod]
        public void Initialize_StudentData_HasCorrectFirstStudent()
        {
            // Arrange
            var dbName = nameof(Initialize_StudentData_HasCorrectFirstStudent);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            var carson = context.Students.Single(s => s.LastName == "Alexander");
            Assert.AreEqual("Carson", carson.FirstMidName);
            Assert.AreEqual("Alexander", carson.LastName);
            Assert.AreEqual(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);
        }

        #endregion

        #region Instructor Data Verification Tests

        [TestMethod]
        public void Initialize_InstructorData_HasCorrectFirstInstructor()
        {
            // Arrange
            var dbName = nameof(Initialize_InstructorData_HasCorrectFirstInstructor);

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            var kim = context.Instructors.Single(i => i.LastName == "Abercrombie");
            Assert.AreEqual("Kim", kim.FirstMidName);
            Assert.AreEqual("Abercrombie", kim.LastName);
            Assert.AreEqual(DateTime.Parse("1995-03-11"), kim.HireDate);
        }

        #endregion

        #region Department Data Verification Tests

        [TestMethod]
        public void Initialize_DepartmentData_HasCorrectDepartmentNames()
        {
            // Arrange
            var dbName = nameof(Initialize_DepartmentData_HasCorrectDepartmentNames);
            var expectedNames = new[] { "Economics", "Engineering", "English", "Mathematics" };

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            var actualNames = context.Departments
                .Select(d => d.Name)
                .OrderBy(n => n)
                .ToArray();

            CollectionAssert.AreEqual(expectedNames, actualNames);
        }

        #endregion

        #region Course Data Verification Tests

        [TestMethod]
        public void Initialize_CourseData_HasCorrectCourseIds()
        {
            // Arrange
            var dbName = nameof(Initialize_CourseData_HasCorrectCourseIds);
            var expectedIds = new[] { 1045, 1050, 2021, 2042, 3141, 4022, 4041 };

            // Act
            using var context = CreateAndSeed(dbName);

            // Assert
            var actualIds = context.Courses
                .Select(c => c.CourseID)
                .OrderBy(id => id)
                .ToArray();

            CollectionAssert.AreEqual(expectedIds, actualIds);
        }

        #endregion
    }
}

